function _mtagGfClamp01(v) { if (v == null) return 0; if (v < 0) return 0; if (v > 1) return 1; return v; }

// Resolve a placeholder token line ("points[0].rampPoint", "points[2].color[1]",
// "points[1].midPoint", "points[3].opacity") against the prepared point list.
function _mtagGfResolve(pts, line) {
    var m = line.match(/points\[(\d+)\]\.(\w+)(?:\[(\d+)\])?/);
    if (!m) return 0;
    var p = pts[parseInt(m[1], 10)];
    if (!p) return 0;
    var field = m[2];
    if (field === "color") return _mtagGfClamp01(p.color[parseInt(m[3], 10)]);
    if (field === "rampPoint") return _mtagGfClamp01(p.rampPoint);
    if (field === "midPoint") return _mtagGfClamp01(p.midPoint);
    if (field === "opacity") return _mtagGfClamp01(p.opacity);
    return 0;
}

// Build the substituted .ffx binary string for `stops` (each {offset, rgba:[r,g,b,a],
// midpoint?}, all 0..1). Returns null if no template fits. Templates cover 2..8
// stops; <2 uses the 2-stop template, >8 is clamped to 8 (extra stops dropped,
// caller should warn). Replication of AEUX createFile's line loop is deliberate
// (rejoining every line with '\n' matches its proven byte layout; any extra
// trailing newline lands in the XMP padding zone, outside RIFF size accounting).
function _mtagBuildGradFfxString(stops) {
    var n = stops.length;
    var tplN = n < 2 ? 2 : (n > 8 ? 8 : n);
    var tpl = _MTAG_GRAD_TEMPLATES["template_grad" + tplN];
    if (!tpl) return null;
    // Prepare exactly tplN points (pad by repeating the last if we somehow have
    // fewer than the template expects, so every points[] token resolves).
    var pts = [];
    for (var i = 0; i < tplN; i++) {
        var s = stops[i] || stops[stops.length - 1];
        var a = (s.rgba[3] == null ? 1 : s.rgba[3]);
        pts.push({
            rampPoint: _mtagGfClamp01(s.offset),
            midPoint: (s.midpoint == null ? 0.5 : _mtagGfClamp01(s.midpoint)),
            opacity: _mtagGfClamp01(a),
            color: [_mtagGfClamp01(s.rgba[0]), _mtagGfClamp01(s.rgba[1]), _mtagGfClamp01(s.rgba[2])]
        });
    }
    var lines = tpl.split("\n");
    var out = "";
    for (var li = 0; li < lines.length; li++) {
        var line = lines[li];
        if (line.search(/points\[/) != -1) {
            line = "<float>" + _mtagGfResolve(pts, line).toFixed(8) + "</float>";
        }
        out += (line + "\n");
    }
    return out;
}

// Write the .ffx string to a temp file with BINARY encoding. Returns the File or null.
function _mtagWriteGradFfx(str) {
    try {
        var f = new File(Folder.temp.fsName + "/mtag_grad.ffx");
        f.encoding = "BINARY";
        if (!f.open("w")) return null;
        f.write(str);
        f.close();
        return f;
    } catch (e) { return null; }
}

// Deselect every selected property in the active comp so applyPreset has a
// single, known target.
function _mtagGfDeselectAll() {
    try {
        var comp = app.project.activeItem;
        if (comp && comp.selectedProperties) {
            for (var sp = comp.selectedProperties.length - 1; sp >= 0; sp--) {
                try { comp.selectedProperties[sp].selected = false; } catch (e1) {}
            }
        }
    } catch (e) {}
}

// PRIMARY path (mirrors AEUX exactly): patch the color stops of an ALREADY
// CREATED gradient property (`gradProp` = a G-Fill or G-Stroke that addProperty
// already produced, with Type/Start/End set the normal way). Selecting that
// property and applying the preset merges the preset's `ADBE Vector Grad Colors`
// leaf onto it. That leaf matchName is shared by G-Fill AND G-Stroke, so the
// same fill templates patch a stroke too -- no G-Stroke template needed. This is
// AE's own serialization, so it carries real N stops + midpoints, unlike the
// reverse-engineered _mtagGradValue setValue. Returns true on success.
function _mtagApplyGradColorsPreset(shapeLayer, gradProp, stops) {
    try {
        if (!shapeLayer || !gradProp) return false;
        var str = _mtagBuildGradFfxString(stops);
        if (!str) return false;
        var f = _mtagWriteGradFfx(str);
        if (!f) return false;
        _mtagGfDeselectAll();
        try { gradProp.selected = true; } catch (eSel) { return false; }
        shapeLayer.applyPreset(f);
        try { gradProp.selected = false; } catch (eU) {}
        return true;
    } catch (e) { return false; }
}

// LAST-RESORT path for AE builds where addProperty("G-Fill") itself throws (AE
// 2026/v26) so no gradient property exists to patch. Applies the preset to the
// group hoping AE CREATES the G-Fill. `groupContents` is the vector group's
// Contents; `shapeLayer` is the AVLayer (Layer.applyPreset is the real API --
// PropertyGroup has none).
//
// UNVERIFIED ON AE 2026 -- this create-via-preset move is NOT what AEUX does
// (AEUX always patches an existing property). It may spawn a detached vector
// group instead of attaching here. Guarded + heuristic-checked so any failure
// degrades to the Gradient Ramp fallback.
// Returns true on apparent success, false to let the caller fall back to Ramp.
function _mtagApplyGradientFillPreset(shapeLayer, groupContents, paint) {
    try {
        var str = _mtagBuildGradFfxString(paint.stops);
        if (!str) return false;
        var f = _mtagWriteGradFfx(str);
        if (!f) return false;
        // Give applyPreset a selection context: select the group meant to
        // receive the fill (AEUX selects the target fill property first).
        _mtagGfDeselectAll();
        try { groupContents.selected = true; } catch (eG) {}
        var before = groupContents.numProperties;
        shapeLayer.applyPreset(f);
        try { shapeLayer.selected = false; } catch (eU) {}
        // Heuristic success check: the group gained a G-Fill operator.
        for (var p = groupContents.numProperties; p >= 1; p--) {
            var pr = groupContents.property(p);
            if (pr && pr.matchName === "ADBE Vector Graphic - G-Fill") return true;
        }
        return groupContents.numProperties > before;
    } catch (e) { return false; }
}
